qry:select.qry:xquery:
				for $r in sql('
	SELECT
		t0.oi_conocimiento as oi_conocimiento,
		t0.c_conocimiento,
		t0.d_conocimiento,
		t0.l_administrativo,
		t0.l_industrial,
		t0.l_informatico,
		t0.l_tecnico,
		t0.l_promotora,
		t0.l_merchandiser,
		t0.o_conocimiento
	FROM
		POS16_CONOCIMIENTOS as t0
	WHERE
		1=1
		{%? (#DATOS:@d_conocimiento!='')
			{% AND t0.d_conocimiento= \'{%= #DATOS:@d_conocimiento %}\'  %}
			{% %}
		%}
		{%? (#DATOS:@c_conocimiento!='')
			{% and t0.c_conocimiento= \'{%= #DATOS:@c_conocimiento %}\'  %}
			{% %}
		%}
		{%? (#DATOS:@l_administrativo!='')
			{% and t0.l_administrativo= {%= #DATOS:@l_administrativo %}  %}
			{% %}
		%}
		{%? (#DATOS:@l_industrial!='')
			{% and t0.l_industrial= {%= #DATOS:@l_industrial %}  %}
			{% %}
		%}
		{%? (#DATOS:@l_informatico!='')
			{% and t0.l_informatico= {%= #DATOS:@l_informatico %}  %}
			{% %}
		%}
		{%? (#DATOS:@l_promotora!='')
			{% and t0.l_promotora= {%= #DATOS:@l_promotora %}  %}
			{% %}
		%}
		{%? (#DATOS:@l_tecnico!='')
			{% and t0.l_tecnico= {%= #DATOS:@l_tecnico %}  %}
			{% %}
		%}
		{%? (#DATOS:@l_merchandiser!='')
			{% and t0.l_merchandiser= {%= #DATOS:@l_merchandiser %}  %}
			{% %}
		%}
	ORDER BY
	{%? (#DATOS:@ATRIB_ORDEN1!='') {% {%=#DATOS:@ATRIB_ORDEN1%} {%? (#DATOS:@ORDEN1!='') {% {%=#DATOS:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}
	oi_conocimiento ASC
')/ROWS/ROW

			for $r in sql('
SELECT
	t0.oi_conocimiento as oi_conocimiento,
	t0.c_conocimiento as c_conocimiento,
	t0.d_conocimiento as d_conocimiento,
	t0.l_administrativo as l_administrativo,
	t0.l_industrial as l_industrial,
	t0.l_informatico as l_informatico,
	t0.l_promotora as l_promotora,
	t0.l_tecnico as l_tecnico,
	t0.c_conocimiento as CODE,
	t0.d_conocimiento as TEXT
FROM
	POS16_CONOCIMIENTOS as t0
WHERE
	1=1
	{%? (#DATOS:@d_conocimiento!='')
		{% AND t0.d_conocimiento= \'{%= #DATOS:@d_conocimiento %}\'  %}
		{% %}
	%}
	{%? (#DATOS:@c_conocimiento!='')
		{% and t0.c_conocimiento= \'{%= #DATOS:@c_conocimiento %}\'  %}
		{% %}
	%}
	{%? (#DATOS:@l_administrativo!='')
		{% and t0.l_administrativo= {%= #DATOS:@l_administrativo %}  %}
		{% %}
	%}
	{%? (#DATOS:@l_industrial!='')
		{% and t0.l_industrial= {%= #DATOS:@l_industrial %}  %}
		{% %}
	%}
	{%? (#DATOS:@l_informatico!='')
		{% and t0.l_industrial= {%= #DATOS:@l_industrial %}  %}
		{% %}
	%}
	{%? (#DATOS:@l_promotora!='')
		{% and t0.l_promotora= {%= #DATOS:@l_promotora %}  %}
		{% %}
	%}
	{%? (#DATOS:@l_tecnico!='')
		{% and t0.l_tecnico= {%= #DATOS:@l_tecnico %}  %}
		{% %}
	%}
	{%? (#DATOS:@l_merchandiser!='')
		{% and t0.l_merchandiser= {%= #DATOS:@l_merchandiser %}  %}
		{% %}
	%}
ORDER BY
{%? (#DATOS:@ATRIB_ORDEN1!='')	{% {%=#DATOS:@ATRIB_ORDEN1%} {%? (#DATOS:@ORDEN1!='') {% {%=#DATOS:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}
	oi_conocimiento asc
	')/ROWS/ROW
